import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"Installing Mods","description":"A step by step guide on how to install mods for Fabric.","frontmatter":{"title":"Installing Mods","description":"A step by step guide on how to install mods for Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"1.21.8/players/installing-mods.md","filePath":"versions/1.21.8/players/installing-mods.md","lastUpdated":1760721669000}`);var s={name:`1.21.8/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installing Mods <a class="header-anchor" href="#h1" aria-label="Permalink to “Installing Mods”">​</a></h1><p>This guide will walk you through installing mods for Fabric using the Minecraft Launcher.</p><p>For third party launchers, you should consult their documentation.</p><h2 id="1-download-the-mod" tabindex="-1">1. Download the Mod <a class="header-anchor" href="#1-download-the-mod" aria-label="Permalink to “1. Download the Mod”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>You should only download mods from sources you trust. For more information on finding mods, see the <a href="./finding-mods">Finding Trustworthy Mods</a> guide.</p></div><p>The majority of mods require Fabric API as well, which can be downloaded from <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> or <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>When downloading mods, ensure that:</p><ul><li>They work on the version of Minecraft you want to play on. A mod that works on version 1.20, for example, might not work on version 1.20.2.</li><li>They are for Fabric and not another mod loader.</li><li>Furthermore, they are for the correct edition of Minecraft (Java Edition).</li></ul><h2 id="2-move-the-mod-to-the-mods-folder" tabindex="-1">2. Move the Mod to the <code>mods</code> Folder <a class="header-anchor" href="#2-move-the-mod-to-the-mods-folder" aria-label="Permalink to “2. Move the Mod to the mods Folder”">​</a></h2><p>The mods folder can be found in the following locations for each operating system.</p><p>You can usually paste these paths into the address bar of your file explorer to quickly navigate to the folder.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Once you&#39;ve found the <code>mods</code> folder, you can move the mod <code>.jar</code> files into it.</p><p><img src="/assets/players/installing-mods.png" alt="Installed mods in the mods folder" loading="lazy"></p><h2 id="3-you-re-done" tabindex="-1">3. You&#39;re Done! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. You&#39;re Done!”">​</a></h2><p>Once you&#39;ve moved the mods into the <code>mods</code> folder, you can open the Minecraft Launcher and select the Fabric profile from the dropdown in the bottom left corner and press play!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft Launcher with Fabric profile selected" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Troubleshooting”">​</a></h2><p>If you encounter any issues whilst following this guide, you can ask for help in the <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p><p>You can also attempt to troubleshoot the issue yourself by reading the troubleshooting pages:</p><ul><li><a href="./troubleshooting/crash-reports">Crash Reports</a></li><li><a href="./troubleshooting/uploading-logs">Uploading Logs</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};